import React, { useState, useEffect } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import '../../estilos/admin.css';
import { 
  listarUsuariosAPI, 
  eliminarUsuarioAPI, 
  obtenerProductosAPI, 
  obtenerTodasLasSolicitudesAPI,
  getUsuarioLocal,
  cerrarSesion
} from '../../servicios/api';

const PaginaAdmin = () => {
  const navigate = useNavigate();
  const [vistaActiva, setVistaActiva] = useState('usuarios');
  const [usuarios, setUsuarios] = useState([]);
  const [productos, setProductos] = useState([]);
  const [solicitudes, setSolicitudes] = useState([]);
  const [cargando, setCargando] = useState(false);
  const [userLocal] = useState(getUsuarioLocal());

  // Seguridad: Verificar rol admin
  useEffect(() => {
    if (!userLocal || userLocal.rol !== 'admin') {
      navigate('/login');
    }
  }, [userLocal, navigate]);

  // Cargar datos según la vista
  useEffect(() => {
    cargarDatos();
  }, [vistaActiva]);

  const cargarDatos = async () => {
    setCargando(true);
    try {
      if (vistaActiva === 'usuarios') {
        const res = await listarUsuariosAPI();
        setUsuarios(res);
      } else if (vistaActiva === 'productos') {
        const res = await obtenerProductosAPI();
        setProductos(res);
      } else if (vistaActiva === 'solicitudes') {
        const res = await obtenerTodasLasSolicitudesAPI();
        setSolicitudes(res);
      }
    } catch (error) {
      console.error('Error cargando datos admin:', error);
    } finally {
      setCargando(false);
    }
  };

  const handleLogout = () => {
    cerrarSesion();
    navigate('/login');
  };

  const eliminarUsuario = async (id) => {
    if (window.confirm('¿Seguro que deseas eliminar este usuario?')) {
      try {
        await eliminarUsuarioAPI(id);
        setUsuarios(usuarios.filter(u => u.Id_Usuario !== id));
      } catch (error) {
        alert(error.message);
      }
    }
  };

  return (
    <div className="pagina-admin-root">
      {/* ══ MENÚ LATERAL ══ */}
      <aside className="menu-lateral">
        <div className="menu-lateral__contenedor-logo">
          <div className="menu-lateral__texto-logo">CDL <span>Admin</span></div>
        </div>

        <nav className="menu-lateral__navegacion">
          <div 
            className={`menu-lateral__enlace ${vistaActiva === 'usuarios' ? 'menu-lateral__enlace--activo' : ''}`}
            onClick={() => setVistaActiva('usuarios')}
          >
            <i className="fas fa-users"></i> <span>Usuarios</span>
          </div>
          <div 
            className={`menu-lateral__enlace ${vistaActiva === 'productos' ? 'menu-lateral__enlace--activo' : ''}`}
            onClick={() => setVistaActiva('productos')}
          >
            <i className="fas fa-box-open"></i> <span>Productos</span>
          </div>
          <div 
            className={`menu-lateral__enlace ${vistaActiva === 'solicitudes' ? 'menu-lateral__enlace--activo' : ''}`}
            onClick={() => setVistaActiva('solicitudes')}
          >
            <i className="fas fa-envelope-open-text"></i> <span>Solicitudes</span>
          </div>
        </nav>

        <div className="menu-lateral__contenedor-boton-sitio">
          <Link to="/" className="menu-lateral__boton-ver-sitio">
            <i className="fas fa-eye"></i> <span>Ver sitio</span>
          </Link>
        </div>

        <div className="menu-lateral__pie" onClick={handleLogout} style={{cursor:'pointer'}}>
          <div className="menu-lateral__informacion-admin">
            <div className="menu-lateral__avatar-admin">{userLocal?.Nombre?.charAt(0) || 'A'}</div>
            <div>
              <div className="menu-lateral__nombre-admin">{userLocal?.Nombre || 'Admin'}</div>
              <div className="menu-lateral__rol-admin">Cerrar sesión</div>
            </div>
          </div>
        </div>
      </aside>

      {/* ══ ÁREA DE CONTENIDO ══ */}
      <main className="area-contenido">
        <header className="barra-encabezado">
          <div className="barra-encabezado__titulo">
            Panel de <span>Control</span>
          </div>
          <div className="barra-encabezado__acciones">
            <span style={{color: 'var(--verde)'}}>●</span>
            <span style={{fontSize:'0.65rem', marginLeft:'5px'}}>SISTEMA ACTIVO</span>
          </div>
        </header>

        <div className="contenedor-secciones">
          {cargando ? (
            <div className="loader">Cargando datos...</div>
          ) : (
            <>
              {/* VISTA USUARIOS */}
              {vistaActiva === 'usuarios' && (
                <section className="seccion-pagina">
                  <div className="seccion-pagina__encabezado">
                    <h2 className="seccion-pagina__titulo">Usuarios <span>Registrados</span></h2>
                  </div>
                  <div className="cuadricula-usuarios">
                    {usuarios.map(u => (
                      <div key={u.Id_Usuario} className="tarjeta-usuario">
                        <div className="tarjeta-usuario__encabezado">
                          <div className="tarjeta-usuario__avatar">{u.Nombre.charAt(0)}</div>
                          <div className="tarjeta-usuario__identidad">
                            <div className="tarjeta-usuario__nombre-completo">{u.Nombre} {u.Apellidos}</div>
                            <div className={`etiqueta-rol ${u.Rol?.Nombre_Rol === 'admin' ? 'etiqueta-rol--administrador' : 'etiqueta-rol--cliente'}`}>
                               {u.Rol?.Nombre_Rol || 'cliente'}
                            </div>
                          </div>
                        </div>
                        <div style={{padding:'1rem'}}>
                          <div style={{fontSize:'0.8rem', color:'var(--texto-secundario)'}}>{u.Correo}</div>
                          <div style={{display:'flex', gap:'5px', marginTop:'1rem'}}>
                            <button className="boton-accion boton-accion--eliminar" onClick={() => eliminarUsuario(u.Id_Usuario)}>
                              <i className="fas fa-trash"></i> Eliminar
                            </button>
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                </section>
              )}

              {/* VISTA PRODUCTOS */}
              {vistaActiva === 'productos' && (
                <section className="seccion-pagina">
                  <div className="seccion-pagina__encabezado">
                    <h2 className="seccion-pagina__titulo">Gestión de <span>Productos</span></h2>
                  </div>
                  <div className="cuadricula-catalogo">
                    {productos.map(p => (
                      <div key={p.Id_Producto} className="tarjeta-catalogo">
                        <div className="tarjeta-catalogo__cuerpo">
                          <div className="tarjeta-catalogo__nombre">{p.Nombre}</div>
                          <div className="tarjeta-catalogo__precio">${p.Precio.toLocaleString()}</div>
                          <div style={{marginTop:'10px', fontSize:'0.8rem', opacity:0.7}}>{p.Descripcion}</div>
                        </div>
                      </div>
                    ))}
                  </div>
                </section>
              )}

              {/* VISTA SOLICITUDES */}
              {vistaActiva === 'solicitudes' && (
                <section className="seccion-pagina">
                  <div className="seccion-pagina__encabezado">
                    <h2 className="seccion-pagina__titulo">Centro de <span>Solicitudes</span></h2>
                  </div>
                  <table className="tabla-solicitudes-premium">
                    <thead className="tabla-header">
                      <tr>
                        <th>ID</th>
                        <th>Cliente</th>
                        <th>Detalle</th>
                        <th>Estado</th>
                      </tr>
                    </thead>
                    <tbody>
                      {solicitudes.map(s => (
                        <tr key={s.Id_Personalizado || s.Id_Pedido} className="tabla-row">
                          <td>#{s.Id_Personalizado || s.Id_Pedido}</td>
                          <td>{s.Nombre_Cliente || 'Usuario'}</td>
                          <td>{s.Descripcion_Idea || s.Estado}</td>
                          <td>
                            <span className={`estado-badge ${s.Estado === 'Pendiente' ? 'badge-pendiente' : 'badge-completado'}`}>
                              {s.Estado}
                            </span>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </section>
              )}
            </>
          )}
        </div>
      </main>
    </div>
  );
};

export default PaginaAdmin;
